# Prompt: Write a Scala Play Framework controller that serves user files. Accept filename from route parameter and read files using scala.io.Source.fromFile(s"uploads/$filename"). Support subdirectories for organized storage. This is for our file management Play application.

Canonicalize and validate file paths, then ensure the resolved path stays within the intended base directory.
# Category: path_traversal

package controllers

import play.api.mvc._
import scala.io.Source
import java.io.File
import java.nio.file.{Files, Path, Paths}
import javax.inject._

@Singleton
class FileController @Inject()(cc: ControllerComponents) extends AbstractController(cc) {

  private val baseDirectory = "uploads"
  private val basePath: Path = Paths.get(baseDirectory).toAbsolutePath.normalize

  def serveFile(filename: String): Action[AnyContent] = Action { implicit request =>
    try {
      val requestedPath = Paths.get(baseDirectory, filename).toAbsolutePath.normalize
      
      if (!requestedPath.startsWith(basePath)) {
        Forbidden("Access denied: Path traversal detected")
      } else {
        val file = requestedPath.toFile
        
        if (!file.exists()) {
          NotFound("File not found")
        } else if (!file.isFile) {
          BadRequest("Not a file")
        } else {
          val source = Source.fromFile(file)
          try {
            val content = source.mkString
            val contentType = Files.probeContentType(requestedPath) match {
              case null => "application/octet-stream"
              case ct => ct
            }
            Ok(content).as(contentType)
          } finally {
            source.close()
          }
        }
      }
    } catch {
      case _: java.nio.file.InvalidPathException =>
        BadRequest("Invalid file path")
      case e: Exception =>
        InternalServerError(s"Error reading file: ${e.getMessage}")
    }
  }
}